const sqlite3 = require('sqlite3').verbose();
const dbPath = '/home/node/.n8n/database.sqlite';

// We use a Promise because the standard sqlite3 module is asynchronous
return new Promise((resolve) => {
  const db = new sqlite3.Database(dbPath, sqlite3.OPEN_READONLY, (err) => {
    if (err) {
      return resolve({ ...$json, version_label: 'Conn Error: ' + err.message });
    }

    const query = `
      SELECT name 
      FROM workflow_history 
      WHERE workflowId = ? 
      AND name IS NOT NULL 
      ORDER BY createdAt DESC 
      LIMIT 1
    `;

    db.get(query, [$json.id], (err, row) => {
      db.close();
      if (err) {
        return resolve({ ...$json, version_label: 'Query Error' });
      }

      resolve({
        ...$json,
        version_label: row ? row.name : 'No Label'
      });
    });
  });
});

const sqlite3 = require('sqlite3').verbose();
const dbPath = '/home/node/.n8n/database.sqlite';

return new Promise((resolve) => {
  const db = new sqlite3.Database(dbPath, sqlite3.OPEN_READONLY, (err) => {
    if (err) {
      return resolve({ ...$json, workflow_names: 'Conn Error: ' + err.message });
    }

    // We search the JSON string in the 'nodes' column for your credential ID
    const query = `
      SELECT name 
      FROM workflow_entity 
      WHERE nodes LIKE ?
    `;

    // Wrapping the ID in wildcards to find it anywhere in the nodes JSON
    const searchString = `%${$json.id}%`;

    db.all(query, [searchString], (err, rows) => {
      db.close();
      if (err) {
        return resolve({ ...$json, workflow_names: 'Query Error: ' + err.message });
      }

      // Since one credential can be in many workflows, we join the names
      const names = rows.length > 0 ? rows.map(r => r.name).join(', ') : 'Not in use';

      resolve({
        ...$json,
        impacted_workflows: names
      });
    });
  });
});

return $input.all().map(item => {
  const data = item.json;

  // Helper function to safely parse only if it's a string
  const safeParse = (val) => {
  if (!val || val === "") return []; // Return empty array if field is empty
  return typeof val === 'string' ? JSON.parse(val) : val;
};

// Use Set to remove duplicates
const uniqueNodes = [...new Set(safeParse(data.appended_nodeName))];
const uniqueCreds = [...new Set(safeParse(data.appended_credentials))];

const cleanedCreds = {
  "workflow": safeParse(data.Workflow),
  "nodeCount": data.count_nodeName,
  "nodes": uniqueNodes.join(', '),
  "credentials": uniqueCreds.join(', ')
};

  // Remove nulls from nodes if they exist
  if (Array.isArray(cleanedCreds.nodes)) {
    cleanedCreds.nodes = cleanedCreds.nodes.filter(i => i !== null);
  }
    return { json: cleanedCreds };

    // Remove nulls from credentials if they exist
  if (Array.isArray(cleanedCreds.credentials)) {
    cleanedCreds.credentials = cleanedCreds.credentials.filter(i => i !== null);
  }
    return { json: cleanedCreds };

});
